#include <cstdint>
#include "glm/glm.hpp"

inline float illum_a(float wavelength_nm)
{
	// Planck's constant constants
	const double c1 = 3.74183e-16; // W*m^2
	const double c2 = 1.4388e-2;   // m*K
	const double T = 2856.0;       // Kelvin

	// Convert wavelength from nm to meters
	double lambda = wavelength_nm * 1e-9;
	return c1 / (std::pow(lambda, 5) * (std::exp(c2 / (lambda * T)) - 1.0));;
}

