#include <vector>
#include <string>
#include <fstream>

inline void load_from_csv(const std::string& file_path, std::vector<glm::vec2>& data, bool linearize = false)
{
	std::ifstream str(file_path);
	if(!str.is_open())
	{
		printf("Failed: %s\n", file_path.c_str());
	}

	while(str.good())
	{
		float x, y;
		str >> x;
		str.get();
		str >> y;
		if(linearize)
		{
			x = powf(10.0, x);
			y = powf(10.0, y);
		}
		data.emplace_back(x, y);
	}

	if(data.back().y > 1e38)
		data.pop_back();

	str.close();
}

inline float sample(const std::vector<glm::vec2>& data, float x)
{
	if(x < data[0].x) return data[0].y;
	if(x >= data.back().x) return data.back().y;

	uint32_t start = 0;
	uint32_t end = data.size();

	while((start + 1) != end)
	{
		uint32_t middle = (start + end) / 2;
		if(x >= data[middle].x) start = middle;
		else                          end = middle;
	}

	float blend = (x - data[start].x) / (data[start + 1].x - data[start].x);
	return glm::mix(data[start].y, data[start + 1].y, blend);
}

inline float inverse_sample(const std::vector<glm::vec2>& data, float y)
{
	if(y < data[0].y) return data[0].x;
	if(y >= data.back().y) return data.back().x;

	uint32_t start = 0;
	uint32_t end = data.size();

	while((start + 1) != end)
	{
		uint32_t middle = (start + end) / 2;
		if(y >= data[middle].y) start = middle;
		else                    end = middle;
	}

	float blend = (y - data[start].y) / (data[start + 1].y - data[start].y);
	return glm::mix(data[start].x, data[start + 1].x, blend);
}

struct PaperProfile
{
	//spectral sensitivity
	std::vector<glm::vec2> r_sens;
	std::vector<glm::vec2> g_sens;
	std::vector<glm::vec2> b_sens;

	//charteristic curves
	std::vector<glm::vec2> r_curve;
	std::vector<glm::vec2> g_curve;
	std::vector<glm::vec2> b_curve;

	//dye couplers
	std::vector<glm::vec2> c_dye;
	std::vector<glm::vec2> m_dye;
	std::vector<glm::vec2> y_dye;

	glm::mat3 sens_to_xyz;
	glm::mat3 xyz_to_sens;
	glm::mat3 dye_to_xyz;
	glm::mat3 xyz_to_dye;

	PaperProfile(const std::string& path = "")
	{
		if(path.length() == 0)
		{
			sens_to_xyz = rec2020_to_xyz;
			xyz_to_sens = xyz_to_rec2020;
			dye_to_xyz  = rec2020_to_xyz;
			xyz_to_dye  = xyz_to_rec2020;
		}
		else
		{
			load_from_csv(path + "log_sensitivity_r.csv", r_sens);
			load_from_csv(path + "log_sensitivity_g.csv", g_sens);
			load_from_csv(path + "log_sensitivity_b.csv", b_sens);
			load_from_csv(path + "density_curve_r.csv", r_curve, true);
			load_from_csv(path + "density_curve_g.csv", g_curve, true);
			load_from_csv(path + "density_curve_b.csv", b_curve, true);
			load_from_csv(path + "dye_density_c.csv", c_dye);
			load_from_csv(path + "dye_density_m.csv", m_dye);
			load_from_csv(path + "dye_density_y.csv", y_dye);

			{
				glm::vec3 rc(0.0f), gc(0.0f), bc(0.0f);
				for(uint32_t i = 360; i < 830; ++i)
				{
					rc += powf(10.0f, sample(r_sens, i)) * cie_xyz_bar[i];
					gc += powf(10.0f, sample(g_sens, i)) * cie_xyz_bar[i];
					bc += powf(10.0f, sample(b_sens, i)) * cie_xyz_bar[i];
				}

				glm::vec3 ab = glm::inverse(glm::mat3(rc, gc, bc)) * d65_xyz;
				rc *= ab.x; gc *= ab.y; bc *= ab.z;

				sens_to_xyz = glm::mat3(rc, gc, bc);
				xyz_to_sens = glm::inverse(sens_to_xyz);
			}

			{
				glm::vec3 rc(0.0f), gc(0.0f), bc(0.0f);
				for(uint32_t i = 360; i < 830; ++i)
				{
					rc += d65[i] * powf(10.0, sample(c_dye, i)) * cie_xyz_bar[i];
					gc += d65[i] * powf(10.0, sample(m_dye, i)) * cie_xyz_bar[i];
					bc += d65[i] * powf(10.0, sample(y_dye, i)) * cie_xyz_bar[i];
				}

				glm::vec3 ab = glm::inverse(glm::mat3(rc, gc, bc)) * d65_xyz;
				rc *= ab.x; gc *= ab.y; bc *= ab.z;

				dye_to_xyz = glm::mat3(rc, gc, bc);
				xyz_to_dye = glm::inverse(dye_to_xyz);
			}

			//white blance curves
			{
				float r18 = 0.18f / inverse_sample(r_curve, 1.0f / 0.18);
				float g18 = 0.18f / inverse_sample(g_curve, 1.0f / 0.18);
				float b18 = 0.18f / inverse_sample(b_curve, 1.0f / 0.18);

				for(uint32_t i = 0; i < r_curve.size(); ++i)
					r_curve[i].x *= r18;

				for(uint32_t i = 0; i < g_curve.size(); ++i)
					g_curve[i].x *= g18;

				for(uint32_t i = 0; i < b_curve.size(); ++i)
					b_curve[i].x *= b18;

				printf("%f, %f, %f\n", 1.0f / sample(r_curve, 0.18f), 1.0f / sample(g_curve, 0.18f), 1.0f / sample(b_curve, 0.18f));
			}
		}
	}
};

struct FilmProfile
{
	//dye couplers
	std::vector<glm::vec2> c_dye;
	std::vector<glm::vec2> m_dye;
	std::vector<glm::vec2> y_dye;

	glm::mat3 dye_to_xyz;
	glm::mat3 xyz_to_dye;

	FilmProfile(const std::string& path)
	{
		load_from_csv(path + "dye_density_c.csv", c_dye);
		load_from_csv(path + "dye_density_m.csv", m_dye);
		load_from_csv(path + "dye_density_y.csv", y_dye);

		glm::vec3 rc(0.0f), gc(0.0f), bc(0.0f);
		for(uint32_t i = 360; i < 830; ++i)
		{
			rc += d65[i] * powf(10.0, sample(c_dye, i)) * cie_xyz_bar[i];
			gc += d65[i] * powf(10.0, sample(m_dye, i)) * cie_xyz_bar[i];
			bc += d65[i] * powf(10.0, sample(y_dye, i)) * cie_xyz_bar[i];
		}

		glm::vec3 ab = glm::inverse(glm::mat3(rc, gc, bc)) * d65_xyz;
		rc *= ab.x; gc *= ab.y; bc *= ab.z;

		dye_to_xyz = glm::mat3(rc, gc, bc);
		xyz_to_dye = glm::inverse(dye_to_xyz);
	}
};

inline glm::mat3 coupling_matrix(FilmProfile& film, PaperProfile& paper)
{
	glm::vec3 c0(0.0f), c1(0.0f), c2(0.0f);
	for(uint32_t i = 360; i < 830; ++i)
	{
		c0.x += d65[i] * powf(10.0, sample(film.c_dye, i)) * powf(10.0, sample(paper.r_sens, i));
		c0.y += d65[i] * powf(10.0, sample(film.c_dye, i)) * powf(10.0, sample(paper.g_sens, i));
		c0.z += d65[i] * powf(10.0, sample(film.c_dye, i)) * powf(10.0, sample(paper.b_sens, i));

		c1.x += d65[i] * powf(10.0, sample(film.m_dye, i)) * powf(10.0, sample(paper.r_sens, i));
		c1.y += d65[i] * powf(10.0, sample(film.m_dye, i)) * powf(10.0, sample(paper.g_sens, i));
		c1.z += d65[i] * powf(10.0, sample(film.m_dye, i)) * powf(10.0, sample(paper.b_sens, i));

		c2.x += d65[i] * powf(10.0, sample(film.y_dye, i)) * powf(10.0, sample(paper.r_sens, i));
		c2.y += d65[i] * powf(10.0, sample(film.y_dye, i)) * powf(10.0, sample(paper.g_sens, i));
		c2.z += d65[i] * powf(10.0, sample(film.y_dye, i)) * powf(10.0, sample(paper.b_sens, i));
	}

	glm::vec3 ab = glm::inverse(glm::mat3(c0, c1, c2)) * glm::vec3(1.0f);
	c0 *= ab.x; c1 *= ab.y; c2 *= ab.z;

	return glm::mat3(c0, c1, c2);
}
